@page "/apply/personal-info"
@rendermode InteractiveServer
@using sv_ead4305f5a0b4426b80a22e7979642b5.Services
@inject WizardState Wizard
@inject NavigationManager Nav

<PageTitle>Apply - Personal Info</PageTitle>

<h3>Step 1: Personal Information</h3>

<EditForm Model="Wizard" OnValidSubmit="Next" FormName="personal-info">
    <div class="mb-3">
        <label class="form-label">Full Name</label>
        <InputText @bind-Value="Wizard.FullName" class="form-control" />
    </div>
    <div class="mb-3">
        <label class="form-label">Email</label>
        <InputText @bind-Value="Wizard.Email" class="form-control" />
    </div>
    <button type="submit" class="btn btn-primary">Next →</button>
</EditForm>

@code {
    protected override void OnInitialized()
    {
        Wizard.SetStep(1);
    }

    private void Next()
    {
        Wizard.CompleteStep(1);
        Nav.NavigateTo("/apply/experience");
    }
}

@page "/apply/experience"
@rendermode InteractiveServer
@using sv_ead4305f5a0b4426b80a22e7979642b5.Services
@inject WizardState Wizard
@inject NavigationManager Nav

<PageTitle>Apply - Experience</PageTitle>

<h3>Step 2: Work Experience</h3>

@foreach (var job in Wizard.Experience)
{
    <div class="card mb-2 p-2">
        <strong>@job.Title</strong> at @job.Company (@job.Years)
    </div>
}

<h5>Add Entry</h5>
<div class="mb-3">
    <label class="form-label">Company</label>
    <InputText @bind-Value="newJob.Company" class="form-control" />
</div>
<div class="mb-3">
    <label class="form-label">Job Title</label>
    <InputText @bind-Value="newJob.Title" class="form-control" />
</div>
<div class="mb-3">
    <label class="form-label">Years</label>
    <InputText @bind-Value="newJob.Years" class="form-control" />
</div>
<button class="btn btn-secondary me-2" @onclick="AddJob">+ Add</button>
<button class="btn btn-outline-secondary me-2" @onclick="Back">← Back</button>
<button class="btn btn-primary" @onclick="Next">Next →</button>

@code {
    private JobEntry newJob = new();

    protected override void OnInitialized()
    {
        Wizard.SetStep(2);
    }

    private void AddJob()
    {
        Wizard.Experience.Add(newJob);
        newJob = new();
    }

    private void Back() => Nav.NavigateTo("/apply/personal-info");

    private void Next()
    {
        Wizard.CompleteStep(2);
        Nav.NavigateTo("/apply/references");
    }
}

@page "/apply/references"
@rendermode InteractiveServer
@using sv_ead4305f5a0b4426b80a22e7979642b5.Services
@inject WizardState Wizard
@inject NavigationManager Nav

<PageTitle>Apply - References</PageTitle>

<h3>Step 3: References</h3>

@foreach (var r in Wizard.References)
{
    <div class="card mb-2 p-2">
        <strong>@r.Name</strong> — @r.Relationship (@r.Phone)
    </div>
}

<h5>Add Reference</h5>
<div class="mb-3">
    <label class="form-label">Name</label>
    <InputText @bind-Value="newRef.Name" class="form-control" />
</div>
<div class="mb-3">
    <label class="form-label">Relationship</label>
    <InputText @bind-Value="newRef.Relationship" class="form-control" />
</div>
<div class="mb-3">
    <label class="form-label">Phone</label>
    <InputText @bind-Value="newRef.Phone" class="form-control" />
</div>
<button class="btn btn-secondary me-2" @onclick="AddRef">+ Add</button>
<button class="btn btn-outline-secondary me-2" @onclick="Back">← Back</button>
<button class="btn btn-primary" @onclick="Next">Next →</button>

@code {
    private Reference newRef = new();

    protected override void OnInitialized()
    {
        Wizard.SetStep(3);
    }

    private void AddRef()
    {
        Wizard.References.Add(newRef);
        newRef = new();
    }

    private void Back() => Nav.NavigateTo("/apply/experience");

    private void Next()
    {
        Wizard.CompleteStep(3);
        Nav.NavigateTo("/apply/review");
    }
}

@page "/apply/review"
@rendermode InteractiveServer
@using sv_ead4305f5a0b4426b80a22e7979642b5.Services
@inject WizardState Wizard
@inject NavigationManager Nav

<PageTitle>Apply - Review</PageTitle>

<h3>Step 4: Review Your Application</h3>

<h5>Personal Information</h5>
<p><strong>Name:</strong> @Wizard.FullName</p>
<p><strong>Email:</strong> @Wizard.Email</p>

<h5>Experience</h5>
@if (Wizard.Experience.Count == 0)
{
    <p class="text-muted">No entries.</p>
}
else
{
    @foreach (var job in Wizard.Experience)
    {
        <p>@job.Title at @job.Company (@job.Years)</p>
    }
}

<h5>References</h5>
@if (Wizard.References.Count == 0)
{
    <p class="text-muted">No entries.</p>
}
else
{
    @foreach (var r in Wizard.References)
    {
        <p>@r.Name — @r.Relationship (@r.Phone)</p>
    }
}

<button class="btn btn-outline-secondary me-2" @onclick="Back">← Back</button>
<button class="btn btn-success" @onclick="Submit">Submit Application</button>

@code {
    protected override void OnInitialized()
    {
        Wizard.SetStep(4);
    }

    private void Back() => Nav.NavigateTo("/apply/references");

    private void Submit()
    {
        Wizard.CompleteStep(4);
        // TODO: persist to database
    }
}

